#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long xa, xb, Xa, Xb;
        scanf("%lld %lld %lld %lld", &xa, &xb, &Xa, &Xb);
        long long ans = (Xa / xa) + (Xb / xb);
        printf("%lld\n", ans);
    }
    return 0;
}

